mples of Keras callback applicationsEarly stopping at minimum lossThis first example shows the creation of a that stops training when the minimum of loss has been reached, by setting the attribute (boolean). Optionally, you can provide an argument to specify how many epochs we should wait before stopping after having reached a local minimum.tf.keras.callbacks.EarlyStopping provides a more complete and general implementation.import numpy as np
class EarlyStoppingAtMinLoss(keras.callbacks.Callback): """Stop training when the loss is at its min, i.e. the loss stops decreasing.
Arguments: patience: Number of epochs to wait after min has been hit. After this number of no improvement, training stops. """
def __init__(self, patience=0): super().__init__() self.patience = patience # best_weights to store the weights at which the minimum loss occurs. self.best_weights = None
def on_train_begin(self, logs=None): # The number of epoch it has waited when loss is no longer minimum. self.wait = 0 # The epoch the training stops at. self.stopped_epoch = 0 # Initialize the best as infinity. self.best = np.inf
def on_epoch_end(self, epoch, logs=None): current = logs.get("loss") if np.less(current, self.best): self.best = current self.wait = 0 # Record the best weights if current results is better (less). self.best_weights = self.model.get_weights() else: self.wait += 1 if self.wait >= self.patience: self.stopped_epoch = epoch self.model.stop_training = True print("Restoring model weights from the end of the best epoch.") self.model.set_weights(self.best_weights)
def on_train_end(self, logs=None): if self.stopped_epoch > 0: print("Epoch %05d: early stopping" % (self.stopped_epoch + 1))
model = get_model() model.fit( x_train, y_train, batch_size=64, steps_per_epoch=5, epochs=30, verbose=0, callbacks=[LossAndErrorPrintingCallback(), EarlyStoppingAtMinLoss()], ) Up to batch 0, the average loss is 23.53. Up to batch 1, the average loss is 480.92. Up to batch 2, the average loss is 328.49. Up to batch 3, the average loss is 248.52. Up to batch 4, the average loss is 200.53. The average loss for epoch 0 is 200.53 and mean absolute error is 8.30. Up to batch 0, the average loss is 5.02. Up to batch 1, the average loss is 5.80. Up to batch 2, the average loss is 5.51. Up to batch 3, the average loss is 5.38. Up to batch 4, the average loss is 5.42. The average loss for epoch 1 is 5.42 and mean absolute error is 1.90. Up to batch 0, the average loss is 5.80. Up to batch 1, the average loss is 6.89. Up to batch 2, the average loss is 6.68. Up to batch 3, the average loss is 6.35. Up to batch 4, the average loss is 6.57. The average loss for epoch 2 is 6.57 and mean absolute error is 2.07. Restoring model weights from the end of the best epoch. Epoch 00003: early stopping <keras.src.callbacks.History at 0x7fd3802cbb80> In this example, we show how a custom Callback can be used to dynamically change the learning rate of the optimizer during the course of training.See callbacks.LearningRateScheduler for a more general implementations.class CustomLearningRateScheduler(keras.callbacks.Callback): """Learning rate scheduler which sets the learning rate according to schedule.
Arguments: schedule: a function that takes an epoch index (integer, indexed from 0) and current learning rate as inputs and returns a new learning rate as output (float). """
def __init__(self, schedule): super().__init__() self.schedule = schedule
def on_epoch_begin(self, epoch, logs=None): if not hasattr(self.model.optimizer, "lr"): raise ValueError('Optimizer must have a "lr" attribute.') # Get the current learning rate from model's optimizer. lr = float(tf.keras.backend.get_value(self.model.optimizer.learning_rate)) # Call schedule function to get the scheduled learning rate. scheduled_lr = self.schedule(epoch, lr) # Set the value back to the optimizer before this epoch starts tf.keras.backend.set_value(self.model.optimizer.lr, scheduled_lr) print("\nEpoch %05d: Learning rate is %6.4f." % (epoch, scheduled_lr))
LR_SCHEDULE = [ # (epoch to start, learning rate) tuples (3, 0.05), (6, 0.01), (9, 0.005), (12, 0.001), ]
def lr_schedule(epoch, lr): """Helper function to retrieve the scheduled learning rate based on epoch.""" if epoch < LR_SCHEDULE[0][0] or epoch > LR_SCHEDULE[-1][0]: return lr for i in range(len(LR_SCHEDULE)): if epoch == LR_SCHEDULE[i][0]: return LR_SCHEDULE[i][1] return lr
model = get_model() model.fit( x_train, y_train, batch_size=64, steps_per_epoch=5, epochs=15, verbose=0, callbacks=[ LossAndErrorPrintingCallback(), CustomLearningRateScheduler(lr_schedule), ], ) Epoch 00000: Learning rate is 0.1000. Up to batch 0, the average loss is 25.33. Up to batch 1, the average loss is 434.31. Up to batch 2, the average loss is 298.47. Up to batch 3, the average loss is 226.43. Up to batch 4, the average loss is 182.22. The average loss for epoch 0 is 182.22 and mean absolute error is 8.09.
